import React, { useEffect, useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from './ui/dialog';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Button } from './ui/button';
import {
  Calendar as CalendarIcon,
  Clock,
  MapPin,
  Phone,
  CheckCircle2,
  User,
} from 'lucide-react';
import { TIME_SLOTS } from '../mock';
import {
  createBooking,
  setIdentity,
  getStoredPhone,
  getStoredName,
  getStoredAddress,
} from '../lib/api';
import { useToast } from '../hooks/use-toast';

function iso(d) {
  return d.toISOString().split('T')[0];
}
function nextDays(n) {
  const out = [];
  const t = new Date();
  for (let i = 0; i < n; i++) {
    const d = new Date(t);
    d.setDate(t.getDate() + i);
    out.push(d);
  }
  return out;
}

export default function BookingDialog({ service, open, onOpenChange }) {
  const [step, setStep] = useState(1);
  const [date, setDate] = useState(iso(new Date()));
  const [slot, setSlot] = useState(TIME_SLOTS[2]);
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [address, setAddress] = useState('');
  const [done, setDone] = useState(false);
  const [busy, setBusy] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    if (open) {
      setStep(1);
      setDone(false);
      setName(getStoredName());
      setPhone(getStoredPhone());
      setAddress(getStoredAddress());
    }
  }, [open]);

  if (!service) return null;
  const days = nextDays(7);

  const confirm = async () => {
    if (!name || !phone || !address) {
      toast({
        title: 'Almost there',
        description: 'Please fill name, phone and address to confirm.',
      });
      return;
    }
    setBusy(true);
    try {
      await createBooking({
        service_id: service.id,
        date,
        slot,
        name,
        phone,
        address,
      });
      setIdentity({ name, phone, address });
      setDone(true);
    } catch (e) {
      toast({
        title: 'Could not create booking',
        description: e?.response?.data?.detail || 'Please try again.',
      });
    } finally {
      setBusy(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="w-[95vw]
    max-w-md
    sm:max-w-lg
    max-h-[90vh]
    overflow-y-auto
    p-0">
        {!done ? (
          <>
            <DialogHeader className="sr-only">
              <DialogTitle>Book {service.title}</DialogTitle>
              <DialogDescription>Choose a date, time and address.</DialogDescription>
            </DialogHeader>

            {/* header */}
            <div className="px-6 pt-6 pb-4 border-b border-white/5">
              <div className="flex items-center gap-3">
                <img
                  src={service.image}
                  alt=""
                  className="h-12 w-12 rounded-xl object-cover ring-1 ring-white/10"
                />
                <div className="min-w-0">
                  <p className="text-[10px] uppercase tracking-[0.16em] font-bold text-emerald-400">
                    Step {step} of 2
                  </p>
                  <p className="text-[17px] font-extrabold tracking-tight truncate">
                    {service.title}
                  </p>
                  <p className="text-[12px] text-zinc-400">
                    {service.duration} · ₹{service.price}
                  </p>
                </div>
              </div>
              {/* stepper */}
              <div className="mt-4 grid grid-cols-2 gap-1">
                <span className="h-1.5 rounded-full bg-emerald-500" />
                <span
                  className={
                    'h-1.5 rounded-full ' +
                    (step >= 2 ? 'bg-emerald-500' : 'bg-white/10')
                  }
                />
              </div>
            </div>

            <div className="px-6 py-5 space-y-5">
              {step === 1 && (
                <>
                  <div>
                    <p className="flex items-center gap-2 text-[11px] uppercase tracking-[0.14em] font-bold text-zinc-300">
                      <CalendarIcon size={13} className="text-emerald-400" /> Date
                    </p>
                    <div className="mt-2.5 flex gap-2 overflow-x-auto pb-1 -mx-1 px-1">
                      {days.map((d) => {
                        const v = iso(d);
                        const active = v === date;
                        return (
                          <button
                            key={v}
                            onClick={() => setDate(v)}
                            className={
                              'shrink-0 flex flex-col items-center justify-center w-[58px] h-[70px] rounded-2xl border transition-colors ' +
                              (active
                                ? 'bg-emerald-500 border-emerald-500 text-[#0a1411]'
                                : 'bg-[#13231e] border-white/10 text-zinc-200 hover:border-emerald-500/50')
                            }
                          >
                            <span className="text-[10px] font-bold uppercase opacity-80">
                              {d.toLocaleDateString('en-US', { weekday: 'short' })}
                            </span>
                            <span className="text-[20px] font-extrabold leading-none mt-1">
                              {d.getDate()}
                            </span>
                            <span className="text-[10px] mt-1 opacity-70">
                              {d.toLocaleDateString('en-US', { month: 'short' })}
                            </span>
                          </button>
                        );
                      })}
                    </div>
                  </div>

                  <div>
                    <p className="flex items-center gap-2 text-[11px] uppercase tracking-[0.14em] font-bold text-zinc-300">
                      <Clock size={13} className="text-emerald-400" /> Time
                    </p>
                    <div className="mt-2.5 grid grid-cols-4 gap-2">
                      {TIME_SLOTS.map((t) => (
                        <button
                          key={t}
                          onClick={() => setSlot(t)}
                          className={
                            'h-10 rounded-xl text-[12px] font-semibold border transition-colors ' +
                            (t === slot
                              ? 'bg-emerald-500/15 border-emerald-500 text-emerald-200'
                              : 'bg-[#13231e] border-white/10 text-zinc-300 hover:border-emerald-500/50')
                          }
                        >
                          {t}
                        </button>
                      ))}
                    </div>
                  </div>

                  <Button
                    onClick={() => setStep(2)}
                    className="w-full h-12 rounded-2xl bg-emerald-500 hover:bg-emerald-400 text-[#0a1411] font-bold text-[15px]"
                  >
                    Continue to details
                  </Button>
                </>
              )}

              {step === 2 && (
                <>
                  <Field
                    icon={User}
                    label="Full name"
                    value={name}
                    onChange={setName}
                    placeholder="e.g. Aanya Sharma"
                  />
                  <Field
                    icon={Phone}
                    label="Phone number"
                    value={phone}
                    onChange={setPhone}
                    placeholder="+91 9XXXX XXXXX"
                    type="tel"
                  />
                  <Field
                    icon={MapPin}
                    label="Visit address"
                    value={address}
                    onChange={setAddress}
                    placeholder="Flat, street, landmark, city"
                  />

                  <div className="rounded-2xl border border-white/10 bg-[#13231e] p-3.5 flex items-center justify-between">
                    <div className="text-[12px] text-zinc-400">
                      <p className="font-semibold text-zinc-200">
                        {new Date(date).toDateString()} · {slot}
                      </p>
                      <p className="text-zinc-500 mt-0.5">Pay after the visit · No advance</p>
                    </div>
                    <div className="text-right">
                      <p className="text-[10px] text-zinc-500 uppercase tracking-wider">Total</p>
                      <p className="text-[18px] font-extrabold text-emerald-300">₹{service.price}</p>
                    </div>
                  </div>

                  <div className="flex gap-2">
                    <Button
                      onClick={() => setStep(1)}
                      variant="outline"
                      className="flex-1 h-12 rounded-2xl bg-transparent border-white/15 text-zinc-200 hover:bg-white/5 hover:text-zinc-50"
                    >
                      Back
                    </Button>
                    <Button
                      disabled={busy}
                      onClick={confirm}
                      className="flex-1 h-12 rounded-2xl bg-emerald-500 hover:bg-emerald-400 text-[#0a1411] font-bold text-[15px]"
                    >
                      {busy ? 'Confirming…' : 'Confirm booking'}
                    </Button>
                  </div>
                </>
              )}
            </div>
          </>
        ) : (
          <div className="p-8 text-center">
            <div className="mx-auto h-16 w-16 rounded-full bg-emerald-500/15 flex items-center justify-center">
              <CheckCircle2 className="text-emerald-400" size={36} />
            </div>
            <h3 className="mt-5 text-[22px] font-extrabold tracking-tight">
              You’re all set, {name.split(' ')[0]}.
            </h3>
            <p className="mt-1 text-[14px] text-zinc-400">
              {service.title} on {new Date(date).toDateString()} at {slot}.
            </p>
            <p className="mt-3 text-[12px] text-zinc-500">
              Our concierge will call {phone} to confirm the pro assigned.
            </p>
            <Button
              onClick={() => onOpenChange(false)}
              className="mt-6 w-full h-12 rounded-2xl bg-emerald-500 hover:bg-emerald-400 text-[#0a1411] font-bold text-[15px]"
            >
              Done
            </Button>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

function Field({ icon: Icon, label, value, onChange, placeholder, type = 'text' }) {
  return (
    <div className="space-y-1.5">
      <Label className="text-[11px] uppercase tracking-[0.14em] font-bold text-zinc-300">
        {label}
      </Label>
      <div className="relative">
        <Icon
          size={15}
          className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500"
        />
        <Input
          type={type}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          className="h-11 pl-9 bg-[#13231e] border-white/10 text-zinc-100 placeholder:text-zinc-500 focus-visible:ring-emerald-500/40"
        />
      </div>
    </div>
  );
}
